insert into country_picks (country_code, flag, country_ko, country_en, country_zh, country_ja, rank_num, name_ko, name_en, name_zh, name_ja, score, popularity, reason_ko, reason_en, reason_zh, reason_ja, source_ko, source_en, source_zh, source_ja, source_url) values
('tw', '🇹🇼', '대만', 'Taiwan', '台灣', '台湾', 1, '오뚜기 금라면', 'Ottogi Gold Ramen', '不倒翁金拉麵', 'オットギ ゴールドラーメン', null, null, '한국 라면 중 비교적 순한 매운맛. 층층이 쌓이는 매운맛과 탱글한 면발, 진한 소고기 국물이 대만인 입맛에 잘 맞음. 강호동 추천 라면으로도 유명.', 'A milder Korean ramen with a layered spice that builds gradually. Rich beef broth and springy noodles suit Taiwanese palates well. Also known as MC Kang Ho-dong''s favorite.', '韓國泡麵中辣度相對溫和，辣感層次豐富，搭配彈牙麵條和濃郁牛肉湯底，非常符合台灣人口味。也是藝人姜虎東愛吃的拉麵。', '韓国ラーメンの中では比較的マイルドな辛さ。層を重ねる辛みともちもち麺、濃いビーフスープが台湾人の口に合う。カン・ホドン推薦でも有名。', 'SNS·뉴스 언급량(화제성) 기준', 'Based on SNS & news mention volume', '依據SNS與新聞提及量（話題熱度）排名', 'SNS・ニュース言及量（話題性）基準', 'https://www.beauty321.com/post/64318'),
('tw', '🇹🇼', '대만', 'Taiwan', '台灣', '台湾', 2, '오뚜기 뚱뚱이 라면', 'Ottogi Thick Ramen', '不倒翁胖呼呼拉麵', 'オットギ ポポ ラーメン', null, null, '납작하고 통통한 면발이 특징. 해물 육수 베이스로 해산물을 싫어하는 사람도 부담 없이 먹을 수 있는 순한 맛. 한번 먹으면 계속 생각난다는 반응.', 'Features flat, thick noodles. Seafood-based broth that''s mild enough for those who don''t like seafood. Reviewers say it''s surprisingly addictive.', '扁寬厚實的麵條為一大特色，海鮮高湯底味道溫和，連不愛海鮮的人也能接受。吃過一次就難以忘懷。', '平たくてもちもちの太麺が特徴。海鮮ベースのスープは海鮮が苦手な人でも食べやすいマイルドな味。一度食べるとクセになるという声も。', 'SNS·뉴스 언급량(화제성) 기준', 'Based on SNS & news mention volume', '依據SNS與新聞提及量（話題熱度）排名', 'SNS・ニュース言及量（話題性）基準', 'https://www.beauty321.com/post/64318'),
('tw', '🇹🇼', '대만', 'Taiwan', '台灣', '台湾', 3, '농심 안성탕면', 'Nongshim Ansungtangmyun', '農心安城湯麵', '農心アンソンタン麺', null, null, '은은하게 매운 사골 국물. SEVENTEEN 정한·강호동이 즐겨 먹는 라면으로 화제가 되며 대만에서도 인기 상승.', 'Mildly spicy beef bone broth. Gained popularity in Taiwan after being endorsed by SEVENTEEN''s Jeonghan and MC Kang Ho-dong.', '微辣牛骨湯底，因SEVENTEEN成員淨漢和姜虎東愛吃而在台灣人氣大漲。', 'ほんのり辛い牛骨スープ。SEVENTEENのジョンハンとカン・ホドンが愛食することで話題となり、台湾でも人気が上昇。', 'SNS·뉴스 언급량(화제성) 기준', 'Based on SNS & news mention volume', '依據SNS與新聞提及量（話題熱度）排名', 'SNS・ニュース言及量（話題性）基準', 'https://www.beauty321.com/post/64318'),
('tw', '🇹🇼', '대만', 'Taiwan', '台灣', '台湾', 4, '농심 너구리', 'Nongshim Neoguri', '農心貉子拉麵', '農心たぬきラーメン', null, null, '굵은 우동면과 너구리 모양 어묵이 특징. 진한 해물 국물과 쫄깃한 면발.', 'Thick udon-style noodles and raccoon-shaped fish cake. Rich seafood broth with chewy noodles.', '粗烏冬麵條和貉子形狀魚板為特色，搭配濃郁海鮮湯底和彈牙麵條。', '太いうどん風麺とたぬき型のかまぼこが特徴。濃い海鮮スープともちもち麺。', 'SNS·뉴스 언급량(화제성) 기준', 'Based on SNS & news mention volume', '依據SNS與新聞提及量（話題熱度）排名', 'SNS・ニュース言及量（話題性）基準', 'https://www.beauty321.com/post/64318'),
('tw', '🇹🇼', '대만', 'Taiwan', '台灣', '台湾', 5, '삼양 크림 불닭볶음면', 'Samyang Cream Buldak', '三養奶油火雞炒麵', 'サムヤン クリームブルダック炒め麺', null, null, '불닭볶음면의 매운맛에 크림 소스를 더해 부드럽게. 핑크 패키지로 눈에 띄며 대만에서 가장 인기 있는 불닭 라인.', 'The fiery buldak with a creamy white sauce that softens the heat. The pink packaging stands out — the most popular buldak variety in Taiwan.', '在火辣的火雞炒麵加入奶油白醬讓口感更滑順，粉紅包裝相當顯眼，是台灣最受歡迎的火雞麵口味。', '激辛ブルダックに白いクリームソースを加えてマイルドに。ピンクのパッケージが目立つ、台湾で最も人気のあるブルダックライン。', 'SNS·뉴스 언급량(화제성) 기준', 'Based on SNS & news mention volume', '依據SNS與新聞提及量（話題熱度）排名', 'SNS・ニュース言及量（話題性）基準', 'https://www.beauty321.com/post/64318');
